defmodule SessionPlug do
  import Plug.Conn

  @cookie_name "_app_session"
  @cookie_opts [
    max_age: 86400,
    http_only: true,
    secure: true,
    same_site: "Lax"
  ]

  def init(opts), do: opts

  def call(conn, _opts) do
    session_cookie = conn.cookies[@cookie_name]
    
    case SessionManager.decode_session(session_cookie) do
      {:ok, session_data} ->
        conn
        |> assign(:current_session, session_data)
        |> assign(:current_user_id, session_data.user_id)
        |> assign(:session_data, session_data.data)
      
      {:error, _reason} ->
        conn
        |> assign(:current_session, nil)
        |> assign(:current_user_id, nil)
        |> assign(:session_data, %{})
    end
  end

  def put_session(conn, user_id, data \\ %{}) do
    session_token = SessionManager.create_session(user_id, data)
    put_resp_cookie(conn, @cookie_name, session_token, @cookie_opts)
  end

  def update_session(conn, updates) do
    session_cookie = conn.cookies[@cookie_name]
    
    case SessionManager.update_session(session_cookie, updates) do
      {:ok, new_session_token} ->
        put_resp_cookie(conn, @cookie_name, new_session_token, @cookie_opts)
      
      {:error, _reason} ->
        conn
    end
  end

  def delete_session(conn) do
    delete_resp_cookie(conn, @cookie_name, @cookie_opts)
  end
end

defmodule DistributedSessionStore do
  use GenServer

  def start_link(opts \\ []) do
    GenServer.start_link(__MODULE__, opts, name: __MODULE__)
  end

