    :ets.new(:sessions, [:set, :public, :named_table, read_concurrency: true])
    {:ok, %{}}
  end

  def store_session(session_id, session_data) do
    binary_data = :erlang.term_to_binary(session_data)
    :ets.insert(:sessions, {session_id, binary_data, System.system_time(:second)})
    :ok
  end

  def get_session(session_id) do
    case :ets.lookup(:sessions, session_id) do
      [{^session_id, binary_data, _timestamp}] ->
        session_data = :erlang.binary_to_term(binary_data, [:safe])
        {:ok, session_data}
      
      [] ->
        {:error, :not_found}
    end
  end

  def delete_session(session_id) do
    :ets.delete(:sessions, session_id)
    :ok
  end

  def cleanup_expired_sessions(max_age \\ 86400) do
    current_time = System.system_time(:second)
    cutoff_time = current_time - max_age
    
    :ets.select_delete(:sessions, [
      {{:_, :_, :"$1"}, [{:<, :"$1", cutoff_time}], [true]}
    ])
  end
end

defmodule SessionController do
  use Phoenix.Controller
  import SessionPlug

  def create(conn, %{"user_id" => user_id, "data" => data}) do
    conn
    |> put_session(user_id, data)
    |> json(%{success: true, message: "Session created"})
  end

  def show(conn, _params) do
    session_data = conn.assigns[:session_data] || %{}
    user_id = conn.assigns[:current_user_id]
    
    json(conn, %{
      user_id: user_id,
      session_data: session_data
    })
  end

  def update(conn, %{"data" => data}) do
    conn
    |> update_session(data)
    |> json(%{success: true, message: "Session updated"})
  end

  def delete(conn, _params) do
    conn
    |> delete_session()
    |> json(%{success: true, message: "Session deleted"})
  end
end